import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import API from '../services/api';
import {
  Container,
  Box,
  Typography,
  Grid,
  Card,
  CardMedia,
  CardContent,
  CardActions,
  Button,
  AppBar,
  Toolbar,
  CircularProgress
} from '@mui/material';

const API_URL = 'http://localhost:5000';

function AppHeader() {
  const nav = useNavigate();
  const logout = () => {
    localStorage.removeItem('token');
    nav('/login');
  };

  return (
    <AppBar position="static">
      <Toolbar>
        <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
          AutoTechnix
        </Typography>
        <Button color="inherit" onClick={logout}>Logout</Button>
      </Toolbar>
    </AppBar>
  );
}

export default function Dashboard() {
  const [cars, setCars] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchCars() {
      try {
        const res = await API.get('/cars/my');
        setCars(res.data);
      } catch (err) {
        console.error("Error fetching cars", err);
      } finally {
        setLoading(false);
      }
    }
    fetchCars();
  }, []);

  return (
    <Box sx={{ flexGrow: 1 }}>
      <AppHeader />
      <Container sx={{ mt: 4, mb: 4 }}>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 4 }}>
          <Typography variant="h4" component="h1">
            My Garage
          </Typography>
          <div>
            <Button component={Link} to="/add-car" variant="contained" sx={{ mr: 2 }}>
              Add Car
            </Button>
            <Button component={Link} to="/create-job" variant="outlined" sx={{ mr: 2 }}>
              New Service Request
            </Button>
            <Button component={Link} to="/track-job" variant="outlined">
              Track Jobs
            </Button>
          </div>
        </Box>

        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', mt: 10 }}>
            <CircularProgress />
          </Box>
        ) : (
          <Grid container spacing={4}>
            {cars.map((car) => (
              <Grid item key={car._id} xs={12} sm={6} md={4}>
                <Card>
                  <CardMedia
                    component="img"
                    height="140"
                    image={car.imageUrl ? `${API_URL}${car.imageUrl}`: 'https://via.placeholder.com/300x140.png?text=No+Image'}
                    alt={`Image of ${car.model}`}
                  />
                  <CardContent>
                    <Typography gutterBottom variant="h5" component="div">
                      {car.model}
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      Reg No: {car.regNo}
                    </Typography>
                  </CardContent>
                  <CardActions>
                    <Button size="small">View Details</Button>
                  </CardActions>
                </Card>
              </Grid>
            ))}
          </Grid>
        )}
      </Container>
    </Box>
  );
}
